import{_ as a,c as i,o as d,a1 as o}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Historial de versiones: Evolución de funcionalidades | opencode-agent-skills","description":"Aprende sobre el historial de evolución del plugin OpenCode Agent Skills. Este tutorial resume todas las actualizaciones principales, correcciones de errores, mejoras arquitectónicas y cambios importantes desde v0.1.0 hasta v0.6.4.","frontmatter":{"title":"Historial de versiones: Evolución de funcionalidades | opencode-agent-skills","sidebarTitle":"Novedades de la versión","subtitle":"Historial de versiones","description":"Aprende sobre el historial de evolución del plugin OpenCode Agent Skills. Este tutorial resume todas las actualizaciones principales, correcciones de errores, mejoras arquitectónicas y cambios importantes desde v0.1.0 hasta v0.6.4.","tags":["Actualización de versión","changelog","Historial de lanzamientos"],"order":3},"headers":[],"relativePath":"es/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"es/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),t={name:"es/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function r(n,e,s,l,c,u){return d(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="historial-de-versiones" tabindex="-1">Historial de versiones <a class="header-anchor" href="#historial-de-versiones" aria-label="Permalink to &quot;Historial de versiones&quot;">​</a></h1><p>Este documento registra todas las actualizaciones de versiones del plugin OpenCode Agent Skills. A través del historial de versiones, puedes comprender la ruta de evolución de las funcionalidades, los problemas solucionados y las mejoras arquitectónicas.</p><div class="tip custom-block"><p class="custom-block-title">Versión actual</p><p>La última versión estable es <strong>v0.6.4</strong> (2026-01-20)</p></div><h2 id="linea-de-tiempo-de-versiones" tabindex="-1">Línea de tiempo de versiones <a class="header-anchor" href="#linea-de-tiempo-de-versiones" aria-label="Permalink to &quot;Línea de tiempo de versiones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Versión</th><th>Fecha de lanzamiento</th><th>Tipo</th><th>Contenido principal</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>Corrección</td><td>Análisis YAML, soporte Claude v2</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>Mejora</td><td>Optimizar sugerencias de habilidades</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>Corrección</td><td>Separar nombre de habilidad y nombre de directorio</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>Mejora</td><td>Evitar recomendaciones repetidas de habilidades cargadas</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>Nueva funcionalidad</td><td>Coincidencia semántica, precomputación de embedding</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>Mejora</td><td>Sugerencias de coincidencia aproximada, refactorización</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>Mejora</td><td>Simplificar método de instalación</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>Mejora</td><td>Búsqueda recursiva de scripts</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>Corrección</td><td>Manejo de enlaces simbólicos</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>Corrección</td><td>Preservar modo de agente</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>Corrección</td><td>Problema de cambio de modelo</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>Nueva funcionalidad</td><td>Funcionalidad de lista de archivos</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>Nueva funcionalidad</td><td>Modo Superpowers</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>Inicial</td><td>4 herramientas, descubrimiento en múltiples ubicaciones</td></tr></tbody></table><h2 id="registro-detallado-de-cambios" tabindex="-1">Registro detallado de cambios <a class="header-anchor" href="#registro-detallado-de-cambios" aria-label="Permalink to &quot;Registro detallado de cambios&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>Correcciones</strong>:</p><ul><li>Se corrigió el análisis del frontmatter YAML para descripciones multilínea de habilidades (soporta sintaxis de bloques <code>|</code> y <code>&gt;</code>), reemplazando el analizador personalizado con la biblioteca <code>yaml</code></li><li>Se agregó soporte para el formato v2 del plugin de Claude, <code>installed_plugins.json</code> ahora usa un array de instalación de plugins en lugar de un solo objeto</li></ul><p><strong>Mejoras</strong>:</p><ul><li>El descubrimiento de caché del plugin Claude Code ahora admite la nueva estructura de directorios anidada (<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>)</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>Mejoras</strong>:</p><ul><li>Se optimizaron las indicaciones de evaluación de habilidades para evitar que el modelo envíe mensajes del tipo &quot;no se necesita habilidad&quot; al usuario (el usuario no ve las indicaciones de evaluación ocultas)</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>Correcciones</strong>:</p><ul><li>La validación de habilidades ahora permite que el nombre del directorio sea diferente del <code>name</code> en el frontmatter de SKILL.md. El <code>name</code> en el frontmatter es el identificador estándar, el nombre del directorio se usa solo para organización. Esto cumple con la especificación Anthropic Agent Skills.</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>Mejoras</strong>:</p><ul><li>La recomendación dinámica de habilidades ahora rastrea las habilidades ya cargadas en cada sesión, evitando recomendar habilidades ya cargadas, reduciendo así indicaciones redundantes y el uso de contexto</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>Nuevas funcionalidades</strong>:</p><ul><li><strong>Coincidencia semántica de habilidades</strong>: Después de la inyección inicial de la lista de habilidades, los mensajes posteriores usan embeddings locales para coincidir con las descripciones de habilidades</li><li>Se agregó la dependencia <code>@huggingface/transformers</code> para la generación local de embeddings (versión cuantificada all-MiniLM-L6-v2)</li><li>Cuando un mensaje coincide con habilidades disponibles, se inyecta una indicación de evaluación de 3 pasos (EVALUATE → DECIDE → ACTIVATE), alentando a cargar habilidades (inspirado en el <a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">artículo de blog</a> de <a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a>)</li><li>Caché de embeddings en disco para coincidencias de baja latencia (~/.cache/opencode-agent-skills/)</li><li>Limpieza de sesiones en el evento <code>session.deleted</code></li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>Nuevas funcionalidades</strong>:</p><ul><li>Se agregaron sugerencias de coincidencia aproximada &quot;¿Te refieres a...&quot; en todas las herramientas (<code>use_skill</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>get_available_skills</code>)</li></ul><p><strong>Mejoras</strong>:</p><ul><li><strong>Cambio importante</strong>: Se renombró la herramienta <code>find_skills</code> a <code>get_available_skills</code> para mayor claridad en el propósito</li><li><strong>Interno</strong>: Se reorganizó el código base en módulos independientes (<code>claude.ts</code>, <code>skills.ts</code>, <code>tools.ts</code>, <code>utils.ts</code>, <code>superpowers.ts</code>) para mejorar la mantenibilidad</li><li><strong>Interno</strong>: Se mejoró la calidad del código eliminando comentarios generados por IA y código innecesario</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>Mejoras</strong>:</p><ul><li>El método de instalación ahora usa el paquete npm a través de OpenCode config, en lugar de git clone + enlace simbólico</li></ul><p><strong>Eliminaciones</strong>:</p><ul><li>Se eliminó <code>INSTALL.md</code> (ya no es necesario después de simplificar la instalación)</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>Mejoras</strong>:</p><ul><li>El descubrimiento de scripts ahora busca recursivamente en todo el directorio de habilidades (profundidad máxima 10), en lugar de solo en el directorio raíz y el subdirectorio <code>scripts/</code></li><li>Los scripts ahora se identifican por ruta relativa (como <code>tools/build.sh</code>) en lugar de por nombre base</li><li>Se renombró el parámetro <code>skill_name</code> a <code>skill</code> en las herramientas <code>read_skill_file</code>, <code>run_skill_script</code> y <code>use_skill</code></li><li>Se renombró el parámetro <code>script_name</code> a <code>script</code> en la herramienta <code>run_skill_script</code></li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>Correcciones</strong>:</p><ul><li>Se corrigió la detección de archivos y directorios para manejar correctamente enlaces simbólicos usando <code>fs.stat</code></li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>Correcciones</strong>:</p><ul><li>Se preservó el modo de agente al inyectar mensajes sintéticos al inicio de la sesión</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>Correcciones</strong>:</p><ul><li>Se corrigió el cambio inesperado de modelo al usar herramientas de habilidades (solución temporal para el issue de opencode #4475) pasando explícitamente el modelo actual en la operación <code>noReply</code></li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>Nuevas funcionalidades</strong>:</p><ul><li>Se agregó una lista de archivos en la salida de <code>use_skill</code></li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>Nuevas funcionalidades</strong>:</p><ul><li>Se agregó soporte para el modo Superpowers</li><li>Se agregó comprobante de lanzamiento</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>Nuevas funcionalidades</strong>:</p><ul><li>Se agregó la herramienta <code>use_skill</code> para cargar el contenido de habilidades en el contexto</li><li>Se agregó la herramienta <code>read_skill_file</code> para leer archivos de soporte en el directorio de habilidades</li><li>Se agregó la herramienta <code>run_skill_script</code> para ejecutar scripts desde el directorio de habilidades</li><li>Se agregó la herramienta <code>find_skills</code> para buscar y listar habilidades disponibles</li><li>Se agregó descubrimiento de habilidades en múltiples ubicaciones (nivel de proyecto, nivel de usuario y ubicaciones compatibles con Claude)</li><li>Se agregó validación de frontmatter conforme a la especificación Anthropic Agent Skills Spec v1.0</li><li>Se agregó inyección automática de lista de habilidades al inicio de la sesión y después de la compresión de contexto</li></ul><p><strong>Nuevos colaboradores</strong>:</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (mantenedor)</li></ul><h2 id="resumen-de-evolucion-de-funcionalidades" tabindex="-1">Resumen de evolución de funcionalidades <a class="header-anchor" href="#resumen-de-evolucion-de-funcionalidades" aria-label="Permalink to &quot;Resumen de evolución de funcionalidades&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Versión de introducción</th><th>Ruta de evolución</th></tr></thead><tbody><tr><td>4 herramientas básicas</td><td>v0.1.0</td><td>v0.5.0 agregó coincidencia aproximada</td></tr><tr><td>Descubrimiento de habilidades en múltiples ubicaciones</td><td>v0.1.0</td><td>v0.4.1 simplificó instalación, v0.6.4 soporta Claude v2</td></tr><tr><td>Inyección automática de contexto</td><td>v0.1.0</td><td>v0.3.0 agregó lista de archivos, v0.6.1 evita recomendaciones repetidas</td></tr><tr><td>Modo Superpowers</td><td>v0.2.0</td><td>Estable continuamente</td></tr><tr><td>Búsqueda recursiva de scripts</td><td>v0.4.0</td><td>v0.3.3 corrigió enlaces simbólicos</td></tr><tr><td>Coincidencia semántica y recomendaciones</td><td>v0.6.0</td><td>v0.6.1 evita repetición, v0.6.3 optimizó indicaciones</td></tr><tr><td>Sugerencias de coincidencia aproximada</td><td>v0.5.0</td><td>Estable continuamente</td></tr></tbody></table><h2 id="descripcion-de-cambios-importantes" tabindex="-1">Descripción de cambios importantes <a class="header-anchor" href="#descripcion-de-cambios-importantes" aria-label="Permalink to &quot;Descripción de cambios importantes&quot;">​</a></h2><h3 id="v0-6-0-funcionalidad-de-coincidencia-semantica" tabindex="-1">v0.6.0: Funcionalidad de coincidencia semántica <a class="header-anchor" href="#v0-6-0-funcionalidad-de-coincidencia-semantica" aria-label="Permalink to &quot;v0.6.0: Funcionalidad de coincidencia semántica&quot;">​</a></h3><p>Se introdujo la capacidad de coincidencia semántica basada en embeddings locales, permitiendo que la IA recomiende automáticamente habilidades relacionadas según el contenido del mensaje del usuario, sin necesidad de que el usuario recuerde los nombres de las habilidades manualmente.</p><ul><li><strong>Detalles técnicos</strong>: Uso del modelo <code>all-MiniLM-L6-v2</code> de HuggingFace (cuantificación q8)</li><li><strong>Mecanismo de caché</strong>: Los resultados de los embeddings se almacenan en caché en <code>~/.cache/opencode-agent-skills/</code> para mejorar la velocidad de coincidencias posteriores</li><li><strong>Proceso de coincidencia</strong>: Mensaje del usuario → embedding → calcular similitud coseno con descripciones de habilidades → Top 5 recomendaciones (umbral 0.35)</li></ul><h3 id="v0-5-0-refactorizacion-y-cambio-de-nombre-de-herramientas" tabindex="-1">v0.5.0: Refactorización y cambio de nombre de herramientas <a class="header-anchor" href="#v0-5-0-refactorizacion-y-cambio-de-nombre-de-herramientas" aria-label="Permalink to &quot;v0.5.0: Refactorización y cambio de nombre de herramientas&quot;">​</a></h3><p>La arquitectura del código se refactorizó a un diseño modular, con nombres de herramientas más claros:</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-actualizacion-del-mecanismo-de-descubrimiento-de-scripts" tabindex="-1">v0.4.0: Actualización del mecanismo de descubrimiento de scripts <a class="header-anchor" href="#v0-4-0-actualizacion-del-mecanismo-de-descubrimiento-de-scripts" aria-label="Permalink to &quot;v0.4.0: Actualización del mecanismo de descubrimiento de scripts&quot;">​</a></h3><p>El descubrimiento de scripts evolucionó de &quot;solo directorio raíz + scripts/&quot; a &quot;búsqueda recursiva en todo el directorio de habilidades&quot; (profundidad máxima 10), soportando una organización de scripts más flexible.</p><h3 id="v0-2-0-integracion-con-superpowers" tabindex="-1">v0.2.0: Integración con Superpowers <a class="header-anchor" href="#v0-2-0-integracion-con-superpowers" aria-label="Permalink to &quot;v0.2.0: Integración con Superpowers&quot;">​</a></h3><p>Se agregó soporte para el modo de flujo de trabajo Superpowers, que requiere instalar la habilidad <code>using-superpowers</code> y establecer la variable de entorno <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>.</p><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver ubicaciones del código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Ruta de archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Número de versión actual</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>Historial de versiones</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>Información clave de versiones</strong>:</p><ul><li><code>v0.6.4</code>: Versión actual (2026-01-20)</li><li><code>v0.6.0</code>: Introducción de coincidencia semántica (2025-12-12)</li><li><code>v0.5.0</code>: Versión refactorizada (2025-12-11)</li><li><code>v0.1.0</code>: Versión inicial (2025-11-26)</li></ul></details>',72)])])}const h=a(t,[["render",r]]);export{p as __pageData,h as default};
